-- pgAdmin: mở Query Tool trên database notification_db rồi chạy toàn bộ file này.
CREATE TABLE IF NOT EXISTS notification_preferences(user_id varchar(40) PRIMARY KEY,email_new_releases boolean NOT NULL DEFAULT true,push_trending boolean NOT NULL DEFAULT false,promo_email boolean NOT NULL DEFAULT false,updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS notifications(id varchar(40) PRIMARY KEY,user_id varchar(40) NOT NULL,title varchar(255) NOT NULL,body text NOT NULL,type varchar(30) NOT NULL DEFAULT 'system',deep_link text,read_at timestamptz,created_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX IF NOT EXISTS idx_notifications_inbox ON notifications(user_id,created_at DESC);
